-- HU QC template: barista/service fields only (no kitchen scoring questions).
UPDATE ManagementFormTemplate
SET
  description = 'QC shift audit for HU (barista & service — no kitchen).',
  fieldsJson = '[{"key":"evaluator_name","label":"Evaluator Name","type":"text","required":true},{"key":"branch_name","label":"Branch Name","type":"text","required":true},{"key":"visit_date","label":"Visit Date","type":"date","required":true},{"key":"shift_time","label":"Shift Time","type":"text","required":true},{"key":"manager_name","label":"Manager on Duty","type":"text","required":false},{"key":"team_uniform_hygiene_ok","label":"هل التزام الفريق بالزي والنظافة الشخصية صحيح","type":"select","required":true,"options":["Yes","No"]},{"key":"drains_clean","label":"هل جميع المصارف نظيفة","type":"select","required":true,"options":["Yes","No"]},{"key":"prep_area_safe","label":"هل منطقة التحضير مرتبة وآمنة","type":"select","required":true,"options":["Yes","No"]},{"key":"delivery_area_clean","label":"هل منطقة التسليم نظيفة ومرتبة","type":"select","required":true,"options":["Yes","No"]},{"key":"safety_tools_available","label":"هل أدوات السلامة متوفرة (قفازات/مطهر/طفاية)","type":"select","required":true,"options":["Yes","No"]},{"key":"customer_service_rating","label":"Customer Service Rating","type":"select","required":true,"options":["Excellent","Good","Average","Needs improvement"]},{"key":"critical_issue","label":"Critical issue found?","type":"checkbox","required":false},{"key":"critical_issue_note","label":"Critical issue note","type":"textarea","required":false},{"key":"evidence_photo_1","label":"Evidence photo 1","type":"photo","required":false},{"key":"evidence_photo_2","label":"Evidence photo 2","type":"photo","required":false},{"key":"weaknesses","label":"Weaknesses (نقاط الضعف)","type":"textarea","required":false},{"key":"recommendations","label":"Recommendations (توصيات للتحسين)","type":"textarea","required":false},{"key":"follow_up_required","label":"Follow-up required in next visit","type":"checkbox","required":false}]',
  updatedAt = datetime('now')
WHERE title = 'Quality Control Visit Report - HU' AND category = 'qc';
